import{_ as e,c as t,o as a,a4 as n}from"./chunks/framework.CzsDe1xi.js";const k=JSON.parse('{"title":"知识点","description":null,"frontmatter":{"lang":"zh-CN","title":"知识点","description":null},"headers":[],"relativePath":"doc/消息队列/Kafka/知识点/index.md","filePath":"packages/doc/src/消息队列/Kafka/知识点/index.md","lastUpdated":1702458087000}'),r={name:"doc/消息队列/Kafka/知识点/index.md"},s=n('<h1 id="asdasdasd" tabindex="-1">asdasdasd <a class="header-anchor" href="#asdasdasd" aria-label="Permalink to &quot;asdasdasd&quot;">​</a></h1><p>1.同一个topic的消息可以被不同的消费组重复消费，这和其他的消息队列很不一样。消息消费完毕后仍然存在直到老化被自动删除 2.一个topic只能被一个分区的一个消费者组的任意一个消费者消费，同一个消费者组负载消费订阅的topic，但只能是一个。 3.kafka的消息是持久化的，消费者的commit offset会被记录在一个__consumer_offsets内部topic中，默认是50个 4.kafka是顺序IO，先写内存，异步写磁盘</p><p>问题： #<a href="https://blog.csdn.net/u013411339/article/details/107572522" target="_blank" rel="noreferrer">https://blog.csdn.net/u013411339/article/details/107572522</a></p><p>10.kafka的延时操作原理？ Kafka 中有多种延时操作，比如延时生产，还有延时拉取（DelayedFetch）、延时数据删除（DelayedDeleteRecords）等。 延时操作创建之后会被加入延时操作管理器（DelayedOperationPurgatory）来做专门的处理。延时操作有可能会超时， 每个延时操作管理器都会配备一个定时器（SystemTimer）来做超时管理， 定时器的底层就是采用时间轮（TimingWheel）实现的。</p><p>#kafka结论</p><p>1.如果Topic A被 Group1 和 Group2订阅，消息会同时发送到这2个group的consumer，互不影响 2.partition 编号是从0开始的 3.同一个Topic的partition只会被同一个Group的consumer消费 一个Group的consumer只会对应一个topic的partition 4.消费者实例的个数不能大于partition数量，否则会有消费实例分配不到任何分区而处于空跑状态 5.对于同一个Group内的消费者来说，一个分区最多只能被一个消费者消费 6.阿里云不建议分区数小于12，否则可能影响消费发送性能；也不建议超过100个，否则易引发消费端Rebalance 7.at least once， 也就是至少投递一次，保证消息不丢失，但是无法保证消息不重复。在出现网络问题、客户端重启时均有可能造成少量重复消息，此时应用消费端如果对消息重复比较敏感（例如订单交易类），则应该做消息幂等。 8.消费失败的处理 消费失败 消息队列Kafka版是按分区逐条消息顺序向前推进消费的，如果消费端拿到某条消息后执行消费逻辑失败，例如应用服务器出现了脏数据，导致某条消息处理失败，等待人工干预，那么有以下两种处理方式：</p><p>失败后一直尝试再次执行消费逻辑。这种方式有可能造成消费线程阻塞在当前消息，无法向前推进，造成消息堆积。 消息队列Kafka版没有处理失败消息的设计，实践中通常会打印失败的消息或者存储到某个服务（例如创建一个Topic专门用来放失败的消息），然后定时检查失败消息的情况，分析失败原因，根据情况处理。</p><p>9.一个Group最好对应一个Topic 10.不保证单个分区内绝对有序，在升级或者宕机时，会发生少量消息乱序（某个分区挂掉后把消息Failover到其它分区）</p><p>11.各自Partition内的offset是有序的</p><p>##网址####</p><ul><li><a href="./">kafka可视化网站：</a></li></ul><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>http://localhost:9111/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><a href="./">zookeeper可视化网站</a></li></ul><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>http://localhost:9110/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><a href="https://zoonavigator.elkozmon.com/en/latest/docker/configuration.html#http-port" target="_blank" rel="noreferrer">https://zoonavigator.elkozmon.com/en/latest/docker/configuration.html#http-port</a><a href="https://github.com/elkozmon/zoonavigator" target="_blank" rel="noreferrer">https://github.com/elkozmon/zoonavigator</a></p><p>#docker-compose.yaml设置中国时区 方式一： environment:</p><ul><li>SET_CONTAINER_TIMEZONE=true</li><li>CONTAINER_TIMEZONE=Asia/Shanghai</li></ul><p>方式二： environment:</p><ul><li>TZ=Asia/Shanghai</li></ul><p>#####kafka设置 参考链接：<a href="https://www.cnblogs.com/xuliang666/p/11871389.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/xuliang666/p/11871389.html</a> listeners listeners就是主要用来定义Kafka Broker的Listener的配置项。</p><p>advertised.listeners advertised.listeners参数的作用就是将Broker的Listener信息发布到Zookeeper中</p><p>inter.broker.listener.name inter.broker.listener.name：专门用于Kafka集群中Broker之间的通信</p><p>listener.security.protocol.map 配置监听者的安全协议的，比如PLAINTEXT、SSL、SASL_PLAINTEXT、SASL_SSL</p><p>listeners 是kafka真正bind的地址</p><p>advertised.listeners 是暴露给外部的listeners，如果没有设置，会用listeners</p><p>内外网分流 listener.security.protocol.map=EXTERNAL:PLAINTEXT,INTERNAL:PLAINTEXT listeners=EXTERNAL://192.168.11.103:9092,INTERNAL://192.168.11.103:9093 inter.broker.listener.name=INTERNAL advertised.listeners=EXTERNAL://192.168.11.103:9094,INTERNAL://192.168.11.103:9093</p><p>参考链接:<a href="https://blog.csdn.net/weixin_38251332/article/details/105638535" target="_blank" rel="noreferrer">https://blog.csdn.net/weixin_38251332/article/details/105638535</a> listeners=INSIDE://0.0.0.0:9092,OUTSIDE://&lt;公网 ip&gt;:端口(或者 0.0.0.0:端口) advertised.listeners=INSIDE://localhost:9092,OUTSIDE://&lt;宿主机ip&gt;:&lt;宿主机暴露的端口&gt; listener.security.protocol.map=INSIDE:SASL_PLAINTEXT,OUTSIDE:SASL_PLAINTEXT kafka_inter_broker_listener_name:inter.broker.listener.name=INSIDE</p><p>listeners=INSIDE://0.0.0.0:9092,OUTSIDE://0.0.0.0:8092(&lt;公网 ip&gt;:端口) advertised.listeners=INSIDE://127.0.0.1:9092,OUTSIDE://hostname:8092(&lt;公网 ip&gt;:端口)</p><p>#1.kafka-connect 链接：<a href="https://docs.confluent.io/platform/current/installation/docker/config-reference.html#kconnect-long-configuration" target="_blank" rel="noreferrer">https://docs.confluent.io/platform/current/installation/docker/config-reference.html#kconnect-long-configuration</a> #2.kafka-connect-datagen kafka测试数据构建 <a href="https://blog.csdn.net/litlit023/article/details/112298723" target="_blank" rel="noreferrer">https://blog.csdn.net/litlit023/article/details/112298723</a> #3.使用Kafka Connect将MySQL数据同步至消息队列Kafka版 <a href="https://help.aliyun.com/document_detail/141688.html" target="_blank" rel="noreferrer">https://help.aliyun.com/document_detail/141688.html</a></p><h1 id="for-testing-small-segments-16mb-and-retention-of-128mb" tabindex="-1">For testing small segments 16MB and retention of 128MB <a class="header-anchor" href="#for-testing-small-segments-16mb-and-retention-of-128mb" aria-label="Permalink to &quot;For testing small segments 16MB and retention of 128MB&quot;">​</a></h1><h2 id="网址" tabindex="-1">网址 <a class="header-anchor" href="#网址" aria-label="Permalink to &quot;网址&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>http://localhost:19091</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>',32),i=[s];function o(l,p,c,d,h,m){return a(),t("div",null,i)}const f=e(r,[["render",o]]);export{k as __pageData,f as default};
